proof_block:
// In this synthetic determinism proof fn the original `set_state` ensures
// appear *only* as the antecedent of the postcondition
// `BIG ==> det_set_state_equal(...)`; they are NOT hypotheses already in
// scope.  Bare `assert(forall|i| <ensures-text>)` therefore fails
// verification (z3 cannot derive the ensures from the requires alone).
// We materialise the page_array-relevant slice of the antecedent under
// `if BIG { ... }`: inside the branch BIG is a hypothesis, so the two
// per-i `forall`s and the per-field equalities at `index` are available
// as facts and z3 can instantiate them on the same `i`.
if (post1_self_.page_array.wf())
    && (post2_self_.page_array.wf())
    && (forall|i: int|
        #![trigger post1_self_.page_array@[i]]
        #![trigger pre_self_.page_array@[i]]
        #![trigger post1_self_.page_array@[i].ref_count]
        #![trigger pre_self_.page_array@[i].ref_count]
        0 <= i < NUM_PAGES && i != index ==> post1_self_.page_array@[i] =~= pre_self_.page_array@[i])
    && (forall|i: int|
        #![trigger post2_self_.page_array@[i]]
        #![trigger pre_self_.page_array@[i]]
        #![trigger post2_self_.page_array@[i].ref_count]
        #![trigger pre_self_.page_array@[i].ref_count]
        0 <= i < NUM_PAGES && i != index ==> post2_self_.page_array@[i] =~= pre_self_.page_array@[i])
    && (post1_self_.page_array@[index as int].addr =~= pre_self_.page_array@[index as int].addr)
    && (post1_self_.page_array@[index as int].is_io_page =~= pre_self_.page_array@[index as int].is_io_page)
    && (post1_self_.page_array@[index as int].rev_pointer =~= pre_self_.page_array@[index as int].rev_pointer)
    && (post1_self_.page_array@[index as int].ref_count =~= pre_self_.page_array@[index as int].ref_count)
    && (post1_self_.page_array@[index as int].owning_container =~= pre_self_.page_array@[index as int].owning_container)
    && (post1_self_.page_array@[index as int].mappings =~= pre_self_.page_array@[index as int].mappings)
    && (post1_self_.page_array@[index as int].io_mappings =~= pre_self_.page_array@[index as int].io_mappings)
    && (post1_self_.page_array@[index as int].state =~= state)
    && (post2_self_.page_array@[index as int].addr =~= pre_self_.page_array@[index as int].addr)
    && (post2_self_.page_array@[index as int].is_io_page =~= pre_self_.page_array@[index as int].is_io_page)
    && (post2_self_.page_array@[index as int].rev_pointer =~= pre_self_.page_array@[index as int].rev_pointer)
    && (post2_self_.page_array@[index as int].ref_count =~= pre_self_.page_array@[index as int].ref_count)
    && (post2_self_.page_array@[index as int].owning_container =~= pre_self_.page_array@[index as int].owning_container)
    && (post2_self_.page_array@[index as int].mappings =~= pre_self_.page_array@[index as int].mappings)
    && (post2_self_.page_array@[index as int].io_mappings =~= pre_self_.page_array@[index as int].io_mappings)
    && (post2_self_.page_array@[index as int].state =~= state)
{
    // Pointwise: each entry of the two page_array views agrees.
    assert forall|i: int| 0 <= i < NUM_PAGES implies
        post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
        if i == index as int {
            // Per-field ensures at `index` pin every field of
            // `page_array@[index]` identically across the two runs:
            // unchanged fields collapse to `pre_self_.page_array@[index]`,
            // and `.state` collapses to the parameter `state` on both runs.
            // The per-field asserts below nudge z3 to chain the two
            // `=~=` equalities through `pre_self_.page_array@[index]`;
            // Page extensionality then lifts these per-field equalities to
            // a whole-`Page` equality.
            assert(post1_self_.page_array@[index as int].addr
                =~= post2_self_.page_array@[index as int].addr);
            assert(post1_self_.page_array@[index as int].is_io_page
                =~= post2_self_.page_array@[index as int].is_io_page);
            assert(post1_self_.page_array@[index as int].rev_pointer
                =~= post2_self_.page_array@[index as int].rev_pointer);
            assert(post1_self_.page_array@[index as int].ref_count
                =~= post2_self_.page_array@[index as int].ref_count);
            assert(post1_self_.page_array@[index as int].owning_container
                =~= post2_self_.page_array@[index as int].owning_container);
            assert(post1_self_.page_array@[index as int].mappings
                =~= post2_self_.page_array@[index as int].mappings);
            assert(post1_self_.page_array@[index as int].io_mappings
                =~= post2_self_.page_array@[index as int].io_mappings);
            assert(post1_self_.page_array@[index as int].state
                =~= post2_self_.page_array@[index as int].state);
        } else {
            // For `i != index`, the in-branch foralls give
            // `post1_self_.page_array@[i] =~= pre_self_.page_array@[i]` and
            // `post2_self_.page_array@[i] =~= pre_self_.page_array@[i]`,
            // so they equal each other by transitivity of `=~=`.
        }
    }
    // Sequence extensionality lifts the pointwise equality to view-level
    // `Seq<Page>` equality, which is what `det_set_state_equal` needs for
    // the `page_array` field (the remaining `PageAllocator` fields are
    // pinned to `pre_self_` by direct `==` ensures on both runs, so z3
    // discharges those trivially when proving the final implication).
    assert(post1_self_.page_array@ =~= post2_self_.page_array@);
}
